import{_ as e,o as t,c as o,ai as i}from"./chunks/framework.D76zamVX.js";const r="/WebUkrainianStuff/pages/hardware/fastfetch.png",b=JSON.parse('{"title":"TV-Box як альтернатива Raspberry Pi","description":"","frontmatter":{},"headers":[],"relativePath":"pages/hardware/tvbox.md","filePath":"pages/hardware/tvbox.md","lastUpdated":1768832025000}'),s={name:"pages/hardware/tvbox.md"};function c(l,a,p,n,m,d){return t(),o("div",null,[...a[0]||(a[0]=[i('<h1 id="tv-box-як-альтернатива-raspberry-pi" tabindex="-1">TV-Box як альтернатива Raspberry Pi <a class="header-anchor" href="#tv-box-як-альтернатива-raspberry-pi" aria-label="Permalink to &quot;TV-Box як альтернатива Raspberry Pi&quot;">​</a></h1><p>Мій перший досвід з Linux був саме з тв приставкою X96 Mini, без апаратного прискорення, WiFi, тощо, але - командна рядок був щось таким-таким.... прекрасним, особливо оновлення системи та застосунків, набагато зручніший аніж у Windows. Зараз ця ж сама приставка використовується як сервер розумного будинку</p><div class="info custom-block"><p class="custom-block-title">INFO</p><p>Бажання зробити з приставки сервер був положений від <a href="https://invd.cakestwix.com/watch?v=c3UK-0nvVho" target="_blank" rel="noreferrer">відео автора ctrlD</a> <a href="https://www.youtube.com/watch?v=c3UK-0nvVho" target="_blank" rel="noreferrer">(YouTube)</a> <a href="https://so1der.github.io/articles/s905-server.html#s905-server" target="_blank" rel="noreferrer">(Текстова версія)</a>.</p></div><h2 id="яку-приставку-вибрати-для-цього" tabindex="-1">Яку приставку вибрати для цього? <a class="header-anchor" href="#яку-приставку-вибрати-для-цього" aria-label="Permalink to &quot;Яку приставку вибрати для цього?&quot;">​</a></h2><p>Можна авжеж шукати конкретну модель, або чи підтримується ли вона Armbian/Debian/Arch Linux ARM/тощо, але ось основні признаки що вона може запустити Лінукс</p><ol><li>Процесор Amlogic S905 (Можуть бути й інші, але цей багато де є)</li><li>Кнопка на платі, яку можна нажати чимось через AV вихід (Саме через цю кнопку приставка грузиться не з EMMC, а з USB) <img src="https://so1der.github.io/images/s905-server/button2.jpg" alt="AV Button"></li><li>Гугл у допомогу 😃</li></ol><p>В моєму випадку це x96 mini на базі S905W (існують на різних процесорах, тому бажано переспрашувати), він гарно підтримується Armbian, але нема Wifi(((</p><h2 id="debian-on-amlogic" tabindex="-1">Debian on Amlogic <a class="header-anchor" href="#debian-on-amlogic" aria-label="Permalink to &quot;Debian on Amlogic&quot;">​</a></h2><div class="info custom-block"><p class="custom-block-title">Посилання на проект</p><p><a href="https://github.com/devmfc/debian-on-amlogic" target="_blank" rel="noreferrer">https://github.com/devmfc/debian-on-amlogic</a></p></div><p>На армбіані були проблеми при встановленні на emmc пам&#39;ять, тому знайшов інший проект для цього діла, база та ж сама, тобто Debian.</p><p>На цій системі я спокійно зміг встановити на emmc, що прискорило завантаження ОС у 4-5 разів!!! Та нагадаю, що SD-Card не любить коли на неї встановлюють ОС, якщо там ще своп є то це death.</p><p>У Readme.md цього проекту можна дізнатися які саме твбоксі тестувалися та які проблеми є(в моєму випадку WiFI).</p><p>Беремо з релізів образ системи на через утиліту dd на флешку</p><p>На розділі boot є файл boot.config, там буде багато box=*, прибираємо # на своїй приставці та зберігаємо.</p><h3 id="встановлення-на-emmc-пам-ять" tabindex="-1">Встановлення на emmc-пам&#39;ять <a class="header-anchor" href="#встановлення-на-emmc-пам-ять" aria-label="Permalink to &quot;Встановлення на emmc-пам&#39;ять&quot;">​</a></h3><p>Після того, як ви запустилися, у домашній директорії буде декілька скриптів, нам потрібні тільки два.</p><div class="tip custom-block"><p class="custom-block-title">aml-multiboot-setup.sh</p><p>Зробить так, щоб стоковий завантажувач запускав спершу з USB систему, хз нащо, але без цього другий скрипт не буде пропускати далі</p></div><div class="tip custom-block"><p class="custom-block-title">aml-install-to-emmc.sh</p><p>Потрібний нам скрипт для встановлення на пам&#39;ять самої приставки, швидкість та стабильність буде набагато краще</p></div><p><img src="'+r+'" alt="fastfetch"></p><h2 id="океи-а-нащо" tabindex="-1">Окей, а нащо? <a class="header-anchor" href="#океи-а-нащо" aria-label="Permalink to &quot;Окей, а нащо?&quot;">​</a></h2><p>Особисто я захотів по-перше, оновити твбокс батькам та вимкнути 2.4G WiFi, по-друге, нарешті з досвідом з лінуксом знову потрогати цей прекрасний лінукс на твбоксі, на якому вперше спробував цю прекрасну ОС, ой, тобто цей во, ядро, так.</p><p>Поставив на цю систему docker та Home Assistant з Zigbee2MQTT. Чому б не залишити на великому сервері? Він зараз не у моїй комнаті де є розумні пристрої й треба якось прокладати мережу зігбі до мене, що буде напевно дорого, ось тому взяв дешевий твбокс котрий живиться з USB 5V та mini-UPS.</p><div class="tip custom-block"><p class="custom-block-title">Встановлення HA</p><p>Пересказувати як встановлював HA не буду т.я є оф підтримка aarch64 та просто скопіював docker-compose.yml з конфігами.</p><p><a href="/WebUkrainianStuff/pages/selfhost/homeassistant">Посилання на пост</a></p></div>',23)])])}const u=e(s,[["render",c]]);export{b as __pageData,u as default};
